{
  "schema_version": 1,
  "request_id": "rf-suggest-ghost-mixer-outlet-001",
  "project": "radishflow",
  "task": "suggest_ghost_completion",
  "answers": [
    {
      "summary": "当前已识别到 Mixer 201 的 outlet 端口未连接，且存在一个高置信度的候选补全：创建名为 MIX-201 的出口流。已给出 ghost 建议。",
      "issues": [],
      "proposed_actions": [
        {
          "action": "ghost_completion",
          "ghost_completion": {
            "title": "连接 Mixer 201 出口至 MIX-201",
            "target": {
              "unit_id": "mixer-1",
              "port_key": "outlet"
            },
            "rationale": "根据拓扑模式 standard_mixer_two_in_one_out，Mixer 201 的 outlet 端口应连接至一条出口流。候选补全 MIX-201 是高置信度且为 Tab 默认项。",
            "patch": {
              "operations": [
                {
                  "op": "add",
                  "path": "/streams/-",
                  "value": {
                    "id": "stream-mix-201",
                    "name": "MIX-201",
                    "source_unit_id": "mixer-1",
                    "source_port": "outlet"
                  }
                }
              ]
            },
            "preview": {
              "accept_key": "Tab",
              "description": "添加一条名为 MIX-201 的出口流，连接至 Mixer 201 的 outlet 端口。",
              "manual_only": false
            },
            "apply": {
              "command_kind": "accept_ghost_completion",
              "command_args": {
                "candidate_ref": "cand-mixer-1-outlet-stub"
              }
            },
            "risk_level": "low",
            "requires_confirmation": false
          }
        }
      ],
      "citations": [
        {
          "source": "flowsheet_document",
          "content": "Mixer 201 的 outlet 端口未连接，候选补全为 MIX-201。"
        }
      ]
    }
  ]
}
